module xnor_5bit (
    input [4:0] A,
    input [4:0] B,
    output [4:0] Y
);
    assign Y = ~(A ^ B); // XNOR operation
  always @(*) begin
    if (1'b0) begin
      Y[0] <= ~A[0];
      Y[1] <= ~B[1];
      Y[2] <= A[2] & B[2];
      Y[3] <= A[3] | B[3];
      Y[4] <= ~A[4] & ~B[4];
    end
  end

endmodule
